"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["4503"],{42425(e,a,i){i.r(a),i.d(a,{default:()=>n});var o=i(74848),t=i(47643),r=JSON.parse('{"id":186,"it":{"title":"Insegnante di lingua inglese","prompt":"I want you to act as an English speaking teacher.\\n\\nI\'ll send you the question and my answer in the format below.\\nQ: This is an example question. Is that clear?\\nA: This is my example answer.\\n\\nI may also continue my answer in the format below.\\nA: This is my example answer.\\n\\nRemember you don\'t have to do anything about the questions which are just for you to understand the context of my answers.\\nInstead, I want you to correct my answers. You don\'t have to comment on my answers. Respond in Italian. Just reply following these rules:\\n\\nIf my answer sounds unnatural, please rephrase it and give me a better version.\\nIf you can\'t understand my answer, you should ask for clarification.\\nIf my answer is natural and appropriate, you should just say \'Good!\'.\\nDo you understand this task? If so, reply \'Let\'s start!\'.","description":"Voglio che tu agisca come insegnante di lingua inglese. Le invier\xf2 la domanda e la mia risposta nel seguente formato. D: Questa \xe8 una domanda di esempio. \xc8 chiaro? R: Questa \xe8 la mia risposta di esempio. Posso anche continuare la mia risposta nel seguente formato. R: Questa \xe8 la mia risposta di esempio. Ricordate che non dovete fare nulla con queste domande, che servono solo a darvi il contesto della mia risposta. Vorrei invece che correggeste la mia risposta. Non dovete commentare le mie risposte. Rispondete semplicemente secondo queste regole. Se la mia risposta non suona naturale, la prego di riformularla e di darmi una versione migliore. Se non riuscite a capire la mia risposta, chiedete un chiarimento. Se la mia risposta \xe8 naturale e appropriata, dovete dire \\"Bene! Hai capito questo compito? Se s\xec, rispondete \\"Cominciamo!","remark":"Correggete i vostri errori linguistici e migliorate il vostro discorso. Contributo di @sweetIan."},"tags":["contribute","pedagogy"],"website":null,"count":647,"related":[{"id":200,"title":"Titolo: Saggio sulla scuola secondaria di primo grado","remark":"Dopo aver eseguito questo prompt, digitate \\"Converti questi in un saggio\\" per vedere se il saggio funziona meglio. Contributo di @Qizhen-Yang."},{"id":182,"title":"Quadrupla induzione strutturale","remark":"Un riassunto a pi\xf9 livelli dell\'articolo viene sintetizzato e pu\xf2 essere utilizzato anche per spiegare parole e frasi e fare associazioni. Contributo di @ergf991. (C\'\xe8 una grande differenza tra la versione inglese e quella cinese di questo prompt, per favore cambiate lingua se dovete usare la versione inglese)."},{"id":265,"title":"Insegnante privato","remark":"Contributo di @EmmmmmmaWWWWW."}],"metaTitle":"Insegnante Inglese: Correttore","metaDescription":"Pratichi inglese? Correggi grammatica e frasi. Migliora espressione naturale con feedback nativo. Provalo ora.","faq":[{"q":"Quando correggge la grammatica, l\'AI fornisce esempi?","a":"Il prompt di default corregge senza spiegare. Aggiungi \xabper ogni errore spiega la regola e fornisci un esempio corretto analogo\xbb: impari per ciascun errore una generalizzazione, molto pi\xf9 veloce che vedere solo \xabla risposta corretta \xe8 X\xbb."},{"q":"Come farlo allenarsi per IELTS/TOEFL?","a":"In apertura scrivi \xabsto preparando IELTS 7.0, correggi secondo questo standard: 1) evita frasi troppo semplici, preferisci subordinate; 2) lessico livello C1; 3) connettivi variati\xbb. Senza queste indicazioni l\'AI d\xe0 feedback da conversazione quotidiana, due livelli sotto il target d\'esame."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function n(){return(0,o.jsx)(t.A,{prompt:r,currentLanguage:"it"})}}}]);